const classifyLossReason = (text) => {
  const t = String(text || '').trim();
  if (!t) return 'мВђмЬ† лѓЄкЄ∞мЮђ';
  if (/нКєнЧИ|кЄ∞мИ†л†•|к≥µл≤Х.*мЪ∞мЬД|нГАмВђ.*к≥µл≤Х/.test(t)) return 'нГАмВђ к≥µл≤Х¬ЈнКєнЧИ мЪ∞мЬД';
  if (/лЛ®к∞А|к∞Ак≤©|лєДмЪ©|кЄИмХ°|мШИмВ∞|м†Ак∞А/.test(t)) return 'лЛ®к∞А к≤љмЯБл†• лґАм°±';
  if (/к≥µл≤Х.*лѓЄ|мД†нШЄ|мЪФкµђ|мК§нОЩ|мЪФм≤≠.*к≥µл≤Х/.test(t)) return 'к≥µл≤Х лѓЄмД†нШЄ';
  if (/мЧ∞лЭљ|лМАмЭС.*мІАмЧ∞|лЛµл≥А.*мІАмЧ∞|мІАмЧ∞|лК¶|л∞Флє†/.test(t)) return 'лМАмЭС мІАмЧ∞';
  if (/м†ЬмХИ|мЮРл£М|мД§к≥Д|мД§л™Е|л∞ЬнСЬ|PT.*лґАм°±/.test(t)) return 'м†ЬмХИ¬ЈмЮРл£М лґАм°±';
  if (/мШБмЧЕ|кіАк≥Д|мєЬлґД|кЄ∞м°і.*мЧЕм≤і|мХИл©і/.test(t)) return 'мШБмЧЕ кіАк≥Д мЧімДЄ';
  if (/нШСмХљ|л≥ЄмВђ|кЈЄл£є|мІАмВђ/.test(t)) return 'нШСмХљ/л≥ЄмВђ к≤∞м†Х';
  return 'кЄ∞нГА';
};

