          // мЮРлПЩ л°ЬкЈЄмЭЄ м†АмЮ•
          localStorage.setItem('autoLogin', JSON.stringify({ id: loginId, password: loginPw }));
          // л™®лУ† мВђмЪ©мЮРмЧРк≤М м†Дм≤і л≥ікЄ∞ кЄ∞л≥Єк∞Т
          setSelectedAssignee('all');
          // л©ФмЭЄ м†СкЈЉ лґИк∞А мВђмЪ©мЮРлКФ лІИмЭінОШмЭімІАл°Ь мЭілПЩ
