        "мЧРмЭімЫРк±імД§":"B","лМАмД±к±імЧЕ":"C","мЛ†м∞љк±імЧЕ":"C","нХШмІДк±імД§":"C","л∞©мИШм°ік±імД§":"C",
        "лСРмШБк±імД§":"C","мШИнЩФк±імД§":"C","м†ЬмЭім†ЬмЭіENG":"C","к±імІДк∞Ьл∞Ь":"B","лПЩк±імФ®мХ§мФ®":"C",
