        "лМАнСЬк±імД§":"B","мЧђл¶Дк±імД§":"S","л™ЕмДЬк±імД§":"C","мЪ∞мШБмЧШлФФмХДмЭі":"C","мИШмВ∞кЄ∞мЧЕ":"C",
        "лѓЄл•ік±імґХ":"C","лСРмШБмЭімХ§мФ®":"B","мЛ†нЩФк±імД§":"B","лђінХЬнХШмЪ∞мІХ":"C","нГЬмШБк±імД§":"B",
        "мЧРмК§мЧ†мЧРмЭі":"C","мЭЉмІДк±імД§":"C","мДЄмЫР":"C","лНФл≤†мК§нКЄ мЭімХ§лєД":"C","м≤≠лЮМк±імД§":"B",
        "мГБлѓЄк±імД§":"C","м†ЬмЭЉнКємИШмЉАлѓЄмєЉ":"C","мЪ∞л¶ђл∞©мЮђк±імД§":"B","м±ДлПДк±імД§":"C","мЬДм¶ИнОШмЭЄнМЕ":"C",
        "мЉАмЭінГСк±імД§":"B","нХЬлєЫ":"C","к≤љнХШмЭімХ§мФ®":"B","мҐЕл™Ек±імД§":"N","л≥ілЭЉмФ®мЧФмФ®":"F",
        "мД±мІДмЧРмК§мЖФл£®мЕШ":"F","мВЉм∞љмЧФмІАлЛИмЦілІБ":"F","нХШмЭАк±імД§":"F","м†ХкіСмЭімЧФмФ®":"B",
