        "л†ИмЭЄл≥імЪ∞нЕМнБђ":"N","лПДк≤љ":"N(S)","мІАк±імФ®мХ§мФ®":"N(A)","лЛ§мВ∞мҐЕнХ©к±імД§":"A","л°ЬмЪік±імД§":"A",
        "нХЬкµ≠м†ДлђЄк±імД§":"N(A)","нЭђлѓЉк±імД§":"N(A)","нЪ®мД±мФ®мХ§мФ®":"N(B)","лМАнЭ•мФ®мХ§мФ®":"N(B)",
        "лМАл°Ьк±імД§":"B","лНХмИШк±імД§":"N(B)","лНФмДЄмЫА":"B","мШИлЮСк±імД§":"N(B)","мЭЉмД±кЄ∞мЧЕ":"N(B)",
        "нТНм†ДмЭімЧФмФ®":"B","лѓЄмВђк±імД§":"N(B)","мДЄмЫРнЛ∞мЧ†":"B","лВШлЕЄмІАмЭМ":"N(B)","мЪ∞м£ЉнЛ∞мХ§мХДмЭі":"N(B)",
        "лД§мШ§нЕНк±імД§":"N(B)","лНФмЮРлЮМ":"N(B)","мК§нГАк±імД§":"B","м£ЉнГЬк±імД§":"N(B)","нГЬк∞Хк±імД§":"N(B)",
        "нГЬмЧ∞к±імД§":"B","м±ДмЪ∞к±імД§":"B","мЧРмЭінФЉнЛ∞к±імД§":"N(B)","нЧ§лЄР":"B","мШБмД±к±імД§":"N",
        "мШИмЛ†к±імД§":"N","м≤≠мЪ∞мЧФмІАлЛИмЦілІБ":"N","лМАмЛ†мЧШмЧФмФ®к±імД§":"N","нГСмЭімХ§мФ®":"N",
