        '2027-09-26': 'мґФмДЭ',
        '2027-09-27': 'мґФмДЭ мЧ∞нЬі',
        '2027-09-28': 'лМАм≤ік≥µнЬімЭЉ(мґФмДЭ)',
        '2027-10-03': 'к∞Ьм≤Ьм†И',
        '2027-10-04': 'лМАм≤ік≥µнЬімЭЉ(к∞Ьм≤Ьм†И)',
        '2027-10-09': 'нХЬкЄАлВ†',
        '2027-10-11': 'лМАм≤ік≥µнЬімЭЉ(нХЬкЄАлВ†)',
        '2027-12-25': 'мД±нГДм†И',
        '2027-12-27': 'лМАм≤ік≥µнЬімЭЉ(мД±нГДм†И)',
        '2028-01-01': 'мЛ†м†Х',
        '2028-01-03': 'лМАм≤ік≥µнЬімЭЉ(мЛ†м†Х)',
        '2028-01-25': 'мД§лВ† мЧ∞нЬі',
        '2028-01-26': 'мД§лВ†',
        '2028-01-27': 'мД§лВ† мЧ∞нЬі',
        '2028-03-01': 'мВЉмЭЉм†И',
        '2028-05-02': 'лґАм≤ШлЛШмШ§мЛ†лВ†',
        '2028-05-05': 'мЦіл¶∞мЭілВ†',
        '2028-06-06': 'нШДмґ©мЭЉ',
        '2028-08-15': 'кіСл≥µм†И',
        '2028-09-13': 'мґФмДЭ мЧ∞нЬі',
