                                                  <button onClick={() => setEditingUserMemos(prev => { const c = { ...prev }; delete c[memoKey]; return c; })} style={{ padding: '4px 12px', borderRadius: '6px', border: '1px solid #e2e8f0', background: 'white', color: '#64748b', fontSize: '11px', fontWeight: '600', cursor: 'pointer' }}>мЈ®мЖМ</button>
