                  <button onClick={() => setSheetTab('export')} style={{ flex: 1, minWidth: '80px', padding: '10px', borderRadius: '8px', border: 'none', fontSize: '13px', fontWeight: '600', cursor: 'pointer', background: sheetTab === 'export' ? '#2563eb' : '#f1f5f9', color: sheetTab === 'export' ? 'white' : '#64748b' }}>лВіл≥ілВікЄ∞</button>
