                                    <pre style={{ fontSize: 10, color: '#475569', whiteSpace: 'pre-wrap', wordBreak: 'break-all', maxHeight: 200, overflow: 'auto', margin: '6px 0 0', fontFamily: 'monospace' }}>{r.ocrTextSnippet}</pre>
